const MAX_VAL = 100000;

/**
 * Segment Tree implementation supporting Range Maximum Query (RMQ) and Point Update (Max).
 * The tree is 1-indexed based on the value range [1, MAX_VAL].
 */
class SegmentTree {
    constructor(size) {
        // Tree size is typically 4*N, where N is the number of leaves (MAX_VAL)
        this.size = size;
        this.tree = new Array(4 * size + 1).fill(0);
    }

    // Internal recursive update function
    // nodeIdx: current node index in tree array
    // start, end: range covered by this node
    // idx: index (value) being updated
    // val: new value to update with (we take the max)
    _update(nodeIdx, start, end, idx, val) {
        if (start === end) {
            // Leaf node reached
            this.tree[nodeIdx] = Math.max(this.tree[nodeIdx], val);
            return;
        }

        const mid = Math.floor((start + end) / 2);
        if (idx <= mid) {
            // Go left
            this._update(2 * nodeIdx, start, mid, idx, val);
        } else {
            // Go right
            this._update(2 * nodeIdx + 1, mid + 1, end, idx, val);
        }

        // Update current node: max of children
        this.tree[nodeIdx] = Math.max(this.tree[2 * nodeIdx], this.tree[2 * nodeIdx + 1]);
    }

    // Public update interface
    update(idx, val) {
        if (idx < 1 || idx > this.size) return;
        this._update(1, 1, this.size, idx, val);
    }

    // Internal recursive query function
    // nodeIdx: current node index
    // start, end: range covered by this node
    // L, R: target query range [L, R]
    _query(nodeIdx, start, end, L, R) {
        // Range represented by node is outside the query range
        if (start > R || end < L || L > R) {
            return 0; // Identity element for max operation
        }

        // Range represented by node is completely within the query range
        if (L <= start && end <= R) {
            return this.tree[nodeIdx];
        }

        // Partially overlaps, recurse
        const mid = Math.floor((start + end) / 2);

        const p1 = this._query(2 * nodeIdx, start, mid, L, R);
        const p2 = this._query(2 * nodeIdx + 1, mid + 1, end, L, R);

        return Math.max(p1, p2);
    }

    // Public query interface for range [L, R]
    query_range(L, R) {
        if (L > R || L < 1 || R > this.size) return 0;
        return this._query(1, 1, this.size, L, R);
    }
}


function solve(nums, k) {
    const N = nums.length;
    if (N === 0) {
        return 0;
    }

    // DP[i][0]: Max score ending at i, sequence ends with DOWN move (nums[i] < previous)
    //           Requires next element > nums[i].
    // DP[i][1]: Max score ending at i, sequence ends with UP move (nums[i] > previous)
    //           Requires next element < nums[i].
    const DP = Array(N).fill(0).map(() => [0, 0]);

    // ST0 stores max(DP[j][0]) keyed by nums[j], used for calculating DP[i][1] (UP move: nums[j] < nums[i])
    const ST0 = new SegmentTree(MAX_VAL);
    // ST1 stores max(DP[j][1]) keyed by nums[j], used for calculating DP[i][0] (DOWN move: nums[j] > nums[i])
    const ST1 = new SegmentTree(MAX_VAL);

    let maxScore = 0;

    for (let i = 0; i < N; i++) {
        const v_i = nums[i];

        // 1. Update Segment Trees for index j = i - k, if available
        if (i >= k) {
            const j = i - k;
            // Update ST0 with DP[j][0] at value nums[j]
            ST0.update(nums[j], DP[j][0]);
            // Update ST1 with DP[j][1] at value nums[j]
            ST1.update(nums[j], DP[j][1]);
        }

        // 2. Calculate DP[i][1] (Sequence ends UP: Previous < nums[i])
        // Requires finding max DP[j][0] such that nums[j] < nums[i]
        let MaxPrev0 = ST0.query_range(1, v_i - 1);

        // Base case: Length 1 subsequence (MaxPrev0 = 0)
        DP[i][1] = v_i + Math.max(0, MaxPrev0);


        // 3. Calculate DP[i][0] (Sequence ends DOWN: Previous > nums[i])
        // Requires finding max DP[j][1] such that nums[j] > nums[i]
        let MaxPrev1 = ST1.query_range(v_i + 1, MAX_VAL);

        // Base case: Length 1 subsequence (MaxPrev1 = 0)
        DP[i][0] = v_i + Math.max(0, MaxPrev1);

        // 4. Update overall maximum score
        maxScore = Math.max(maxScore, DP[i][0], DP[i][1]);
    }

    return maxScore;
}

